import { useMqtt } from "../hooks/useMQTT";
 
const Dashboard = ({ sensorName }) => {

    const { messages, connected, error, clearMessages } = useMqtt("test_sensor");
 
    return (
<div>

            {/* Connection status */}
<div className="mb-3">
<span className={`badge ${connected ? "bg-success" : "bg-danger"}`}>

                    {connected ? "Live" : "Disconnected"}
</span>

                {error && (
<span className="text-danger small ms-2">
<i className="bi bi-exclamation-circle me-1"></i>

                        {error}
</span>

                )}
</div>
 
            {/* Live messages */}
<div>

                {messages.length === 0 && (
<p className="text-muted">Waiting for data...</p>

                )}

                {messages.map((msg, i) => (
<div key={i} className="mb-2 p-2 border rounded">
<small className="text-muted">

                            {msg.receivedAt.toLocaleTimeString()}
</small>
<pre className="mb-0 mt-1">

                            {JSON.stringify(msg.data, null, 2)}
</pre>
</div>

                ))}
</div>
 
            {messages.length > 0 && (
<button

                    className="btn btn-sm btn-outline-secondary mt-2"

                    onClick={clearMessages}
>

                    Clear
</button>

            )}
</div>

    );

};
 
export default Dashboard;
